public double solve(final UnivariateRealFunction f, double min, double max, double initial) throws MaxIterationsExceededException, FunctionEvaluationException {
    if (f == null) {
        throw new NullPointerException("Function cannot be null");
    }
    if (min >= max) {
        throw new IllegalArgumentException("Min should be less than Max");
    }
    double mid = 0;
    final double tolerance = 1.0e-8;
    final int maxIterations = 1000;
    int iterations = 0;
    double fMin = f.value(min);
    double fMax = f.value(max);
    if (fMin * fMax > 0) {
        throw new IllegalArgumentException("Function values at endpoints must have opposite signs");
    }
    while ((max - min) > tolerance && iterations < maxIterations) {
        mid = (min + max) / 2;
        double fMid = f.value(mid);
        if (fMid == 0.0) {
            return mid; // Found exact root
        } else if (fMid * fMin < 0) {
            max = mid;
            fMax = fMid;
        } else {
            min = mid;
            fMin = fMid;
        }
        iterations++;
    }
    if (iterations == maxIterations) {
        throw new MaxIterationsExceededException(maxIterations);
    }
    return mid;
}

public double solve(final UnivariateRealFunction f, double min, double max, double initial) throws MaxIterationsExceededException, FunctionEvaluationException {
    if (f == null) {
        throw new IllegalArgumentException("Function cannot be null");
    }
    if (min >= max) {
        throw new IllegalArgumentException("Invalid interval: min must be less than max");
    }
    double mid = 0;
    double fmin = f.value(min);
    double fmax = f.value(max);
    if (fmin * fmax > 0) {
        throw new IllegalArgumentException("The function must have opposite signs at the endpoints");
    }
    if (Math.abs(max - min) <= getAbsoluteAccuracy()) {
        return (min + max) / 2;
    }
    while (Math.abs(max - min) > getAbsoluteAccuracy()) {
        mid = (min + max) / 2;
        double fmid = f.value(mid);
        if (fmid == 0) {
            return mid;
        } else if (fmin * fmid < 0) {
            max = mid;
            fmax = fmid;
        } else {
            min = mid;
            fmin = fmid;
        }
    }
    return (min + max) / 2;
}
